  amrex::Real chi = network_rp::chi;

  // PREPROCESS_ODE

  const amrex::Real cse0 = 6.3999999999999996e-10*nden(0)*nden(4);
  const amrex::Real cse1 = -cse0;
  const amrex::Real cse2 = std::sqrt(tgas);
  const amrex::Real cse3 = cse2/nden(2);
